void test_CB_96_0000()
{
    if (skip_test_CB_96_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();
    auto mmapResult = mmap.Initialize(MinRomBankCount, MinVramBankCount, 1, MinWramBankCount);
    TEST_ASSERT_(mmapResult.IsSuccess(), "%s", mmapResult.GetStatusDescription());

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0xF4D5);
    WriteRegisterWord(RegisterType::SP, 0xB8B8);
    WriteRegisterByte(RegisterType::A, 0xBB);
    WriteRegisterByte(RegisterType::B, 0x09);
    WriteRegisterByte(RegisterType::C, 0x70);
    WriteRegisterByte(RegisterType::D, 0x61);
    WriteRegisterByte(RegisterType::E, 0xE5);
    WriteRegisterFlag(0xD0);
    WriteRegisterByte(RegisterType::H, 0x3E);
    WriteRegisterByte(RegisterType::L, 0x2C);
    mmap.DisableIME();
    WriteRegisterByte(RegisterType::IE, 0x00);
    WriteMemory(0xF4D6, 0x96);
    WriteMemory(0xF4D5, 0xCB);
    WriteMemory(0x3E2C, 0xA7);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 16);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0xBB);
    CheckRegisterByte(RegisterType::B, 0x09);
    CheckRegisterByte(RegisterType::C, 0x70);
    CheckRegisterByte(RegisterType::D, 0x61);
    CheckRegisterByte(RegisterType::E, 0xE5);
    CheckRegisterFlag(0xD0);
    CheckRegisterByte(RegisterType::H, 0x3E);
    CheckRegisterByte(RegisterType::L, 0x2C);
    CheckRegisterWord(RegisterType::PC, 0xF4D7);
    CheckRegisterWord(RegisterType::SP, 0xB8B8);
    TEST_ASSERT(!mmap.IMEEnabled());
    CheckMemory(0x3E2C, 0xA3);
    CheckMemory(0xF4D5, 0xCB);
    CheckMemory(0xF4D6, 0x96);
}

